import json
import boto3
import os
from datetime import datetime
from typing import Dict, Any, Optional

sns_client = boto3.client('sns')

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    """
    Lambda function to publish messages to SNS topics.
    
    Expected event structure:
    {
        "topic_arn": "arn:aws:sns:region:account-id:topic-name",
        "message": "Message content or dict for JSON",
        "subject": "Optional subject line",
        "notification_type": "email|sms|json|raw",
        "message_attributes": {
            "key": {"DataType": "String", "StringValue": "value"}
        },
        "phone_number": "Optional for direct SMS",
        "message_group_id": "Optional for FIFO topics",
        "message_deduplication_id": "Optional for FIFO topics"
    }
    """
    
    try:
        topic_arn = event.get('topic_arn')
        message = event.get('message')
        subject = event.get('subject', '')
        notification_type = event.get('notification_type', 'raw')
        message_attributes = event.get('message_attributes', {})
        phone_number = event.get('phone_number')
        message_group_id = event.get('message_group_id')
        message_deduplication_id = event.get('message_deduplication_id')
        
        if phone_number:
            response = publish_sms(phone_number, message, message_attributes)
        elif not topic_arn:
            return {
                'statusCode': 400,
                'body': json.dumps({
                    'error': 'topic_arn or phone_number is required'
                })
            }
        else:
            response = publish_to_topic(
                topic_arn=topic_arn,
                message=message,
                subject=subject,
                notification_type=notification_type,
                message_attributes=message_attributes,
                message_group_id=message_group_id,
                message_deduplication_id=message_deduplication_id
            )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message published successfully',
                'message_id': response['MessageId'],
                'sequence_number': response.get('SequenceNumber')
            })
        }
        
    except Exception as e:
        print(f"Error publishing message: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': f'Failed to publish message: {str(e)}'
            })
        }


def publish_to_topic(
    topic_arn: str,
    message: Any,
    subject: str = '',
    notification_type: str = 'raw',
    message_attributes: Optional[Dict] = None,
    message_group_id: Optional[str] = None,
    message_deduplication_id: Optional[str] = None
) -> Dict[str, Any]:
    """
    Publish message to SNS topic based on notification type.
    """
    
    formatted_message = format_message(message, notification_type)
    
    publish_params = {
        'TopicArn': topic_arn,
        'Message': formatted_message
    }
    
    if subject:
        publish_params['Subject'] = subject[:100]
    
    if message_attributes:
        publish_params['MessageAttributes'] = message_attributes
    
    if notification_type == 'json':
        publish_params['MessageStructure'] = 'json'
    
    if message_group_id:
        publish_params['MessageGroupId'] = message_group_id
    
    if message_deduplication_id:
        publish_params['MessageDeduplicationId'] = message_deduplication_id
    
    response = sns_client.publish(**publish_params)
    
    return response


def format_message(message: Any, notification_type: str) -> str:
    """
    Format message based on notification type.
    """
    
    if notification_type == 'email':
        return format_email_message(message)
    elif notification_type == 'sms':
        return format_sms_message(message)
    elif notification_type == 'json':
        return format_json_message(message)
    else:
        if isinstance(message, dict) or isinstance(message, list):
            return json.dumps(message)
        return str(message)


def format_email_message(message: Any) -> str:
    """
    Format message for email notifications.
    """
    
    if isinstance(message, dict):
        if 'body' in message:
            email_body = message['body']
            if 'header' in message:
                email_body = f"{message['header']}\n\n{email_body}"
            if 'footer' in message:
                email_body = f"{email_body}\n\n{message['footer']}"
            return email_body
        else:
            formatted = []
            for key, value in message.items():
                formatted.append(f"{key}: {value}")
            return "\n".join(formatted)
    
    return str(message)


def format_sms_message(message: Any) -> str:
    """
    Format message for SMS notifications (160 character limit consideration).
    """
    
    if isinstance(message, dict):
        if 'sms_body' in message:
            return message['sms_body'][:160]
        elif 'body' in message:
            return message['body'][:160]
        else:
            return json.dumps(message)[:160]
    
    return str(message)[:160]


def format_json_message(message: Any) -> str:
    """
    Format message for JSON structure supporting multiple protocols.
    """
    
    if isinstance(message, dict) and 'default' in message:
        return json.dumps(message)
    
    if isinstance(message, dict):
        json_message = {
            'default': json.dumps(message) if not isinstance(message.get('default'), str) else message.get('default', 'Notification')
        }
        
        if 'email' in message:
            json_message['email'] = message['email']
        
        if 'sms' in message:
            json_message['sms'] = message['sms']
        
        if 'http' in message:
            json_message['http'] = message['http']
        
        if 'https' in message:
            json_message['https'] = message['https']
        
        if 'sqs' in message:
            json_message['sqs'] = message['sqs']
        
        if 'lambda' in message:
            json_message['lambda'] = message['lambda']
        
        return json.dumps(json_message)
    
    default_message = str(message)
    return json.dumps({
        'default': default_message,
        'email': default_message,
        'sms': default_message[:160]
    })


def publish_sms(
    phone_number: str,
    message: Any,
    message_attributes: Optional[Dict] = None
) -> Dict[str, Any]:
    """
    Publish SMS directly to a phone number.
    """
    
    formatted_message = format_sms_message(message)
    
    publish_params = {
        'PhoneNumber': phone_number,
        'Message': formatted_message
    }
    
    if message_attributes:
        publish_params['MessageAttributes'] = message_attributes
    else:
        publish_params['MessageAttributes'] = {
            'AWS.SNS.SMS.SMSType': {
                'DataType': 'String',
                'StringValue': 'Transactional'
            }
        }
    
    response = sns_client.publish(**publish_params)
    
    return response


def publish_batch_messages(events: list) -> Dict[str, Any]:
    """
    Publish multiple messages in batch.
    """
    
    results = {
        'successful': [],
        'failed': []
    }
    
    for event in events:
        try:
            topic_arn = event.get('topic_arn')
            message = event.get('message')
            subject = event.get('subject', '')
            notification_type = event.get('notification_type', 'raw')
            message_attributes = event.get('message_attributes', {})
            
            response = publish_to_topic(
                topic_arn=topic_arn,
                message=message,
                subject=subject,
                notification_type=notification_type,
                message_attributes=message_attributes
            )
            
            results['successful'].append({
                'topic_arn': topic_arn,
                'message_id': response['MessageId']
            })
            
        except Exception as e:
            results['failed'].append({
                'topic_arn': event.get('topic_arn'),
                'error': str(e)
            })
    
    return results


def publish_alert_notification(
    topic_arn: str,
    alert_level: str,
    alert_title: str,
    alert_message: str,
    metadata: Optional[Dict] = None
) -> Dict[str, Any]:
    """
    Publish structured alert notification.
    """
    
    timestamp = datetime.utcnow().isoformat()
    
    alert_data = {
        'alert_level': alert_level,
        'title': alert_title,
        'message': alert_message,
        'timestamp': timestamp
    }
    
    if metadata:
        alert_data['metadata'] = metadata
    
    message_attributes = {
        'alert_level': {
            'DataType': 'String',
            'StringValue': alert_level
        },
        'timestamp': {
            'DataType': 'String',
            'StringValue': timestamp
        }
    }
    
    json_message = {
        'default': f"{alert_level}: {alert_title}",
        'email': f"Alert Level: {alert_level}\nTitle: {alert_title}\n\n{alert_message}\n\nTimestamp: {timestamp}",
        'sms': f"{alert_level}: {alert_title}"[:160],
        'lambda': json.dumps(alert_data),
        'sqs': json.dumps(alert_data)
    }
    
    return publish_to_topic(
        topic_arn=topic_arn,
        message=json_message,
        subject=f"{alert_level}: {alert_title}",
        notification_type='json',
        message_attributes=message_attributes
    )


def publish_event_notification(
    topic_arn: str,
    event_type: str,
    event_data: Dict[str, Any],
    correlation_id: Optional[str] = None
) -> Dict[str, Any]:
    """
    Publish event notification with structured data.
    """
    
    timestamp = datetime.utcnow().isoformat()
    
    notification_data = {
        'event_type': event_type,
        'event_data': event_data,
        'timestamp': timestamp
    }
    
    if correlation_id:
        notification_data['correlation_id'] = correlation_id
    
    message_attributes = {
        'event_type': {
            'DataType': 'String',
            'StringValue': event_type
        },
        'timestamp': {
            'DataType': 'String',
            'StringValue': timestamp
        }
    }
    
    if correlation_id:
        message_attributes['correlation_id'] = {
            'DataType': 'String',
            'StringValue': correlation_id
        }
    
    return publish_to_topic(
        topic_arn=topic_arn,
        message=notification_data,
        subject=f"Event: {event_type}",
        notification_type='json',
        message_attributes=message_attributes
    )